import torch
import torchvision
from torchvision import transforms
from PIL import Image
import io
import requests

class ImageClassificationAPI:
    def __init__(self):
        self.model = torchvision.models.resnet18(pretrained=True)
        self.transform = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])

    def predict(self, image):
        # Validate input
        if not isinstance(image, Image.Image):
            raise ValueError("Input must be a PIL Image object")

        # Preprocess input
        image = self.transform(image)

        # Run inference on preprocessed input
        output = self.model(image)

        # Return predicted class and confidence score
        return torch.argmax(output), torch.softmax(output, dim=1)[0]

# Example usage:
api = ImageClassificationAPI()
image = requests.post("http://example.com/image", files={"image": open("image.jpg", "rb")})
prediction = api.predict(image)
print(f"Predicted class: {prediction[0]} with confidence score: {prediction[1].item()}")